@startuml
' Define color scheme
skinparam backgroundColor #FFFFFF
skinparam class {
  BackgroundColor #F5F5F5
  BorderColor #333333
  FontColor #000000
}

' Define class styles
class Capitan {
  <<class>>
  nombre: String
  apellido: String
  matricula: int
  +Capitan(nombre String, apellido String, matricula int): void
}

class Embarcacion {
  <<abstract>>
  capitan: Capitan
  precioBase: double
  valorAdicional: double
  AñoDeFabricacion: int
  +montoDeAlquiler(): double
}

class Yate {
  <<class>>
  cantCamarotes: int
  +compareTo(o Object): int
}

class Velero {
  <<class>>
  cantMastiles: int
  +esGrande(): boolean
}

interface Comparable {
  <<interface>>
  +compareTo(o Object): int
}

' Relationships
Capitan "1" --> "1" Embarcacion
Embarcacion <|-- Yate
Embarcacion <|-- Velero
Yate ..|> Comparable

' Styling
class Capitan {
  BackgroundColor #E8F5E9
  BorderColor #4CAF50
}

class Embarcacion {
  BackgroundColor #E3F2FD
  BorderColor #2196F3
}

class Yate {
  BackgroundColor #E8F5E9
  BorderColor #4CAF50
}

class Velero {
  BackgroundColor #E8F5E9
  BorderColor #4CAF50
}

interface Comparable {
  BackgroundColor #F3E5F5
  BorderColor #9C27B0
}

@enduml
